def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Input for this specific run
    request_type = 'airtable_customer_list'
    product_id = 'P101'
    mongo_db_name_product = 'inventory'
    mongo_collection_name = 'Products'
    airtable_base_id = 'appDEF'
    airtable_table_name = 'Customers'
    mongo_db_name_stats = 'sales_data'

    execution_log.append(f"Processing request_type: {request_type}")

    final_result_obj = {}

    if request_type == 'mongo_product_lookup':
        execution_log.append("Branch A triggered: MongoDB Product Lookup")
        execution_log.append(f"Step 1: Calling mongodb_find with database='{mongo_db_name_product}', collection='{mongo_collection_name}', filter={{'_id': '{product_id}'}}, projection={{'name': 1, 'price': 1, '_id': 0}}")
        raw_result = call_tool('mongodb_find', {
            'database': mongo_db_name_product,
            'collection': mongo_collection_name,
            'filter': {'_id': product_id},
            'projection': {'name': 1, 'price': 1, '_id': 0}
        })
        execution_log.append(f"[RAW] {str(raw_result)[:200]}")
        find_result = json.loads(raw_result) if isinstance(raw_result, str) else raw_result
        final_result_obj = {'query_type': request_type, 'data': find_result}
    elif request_type == 'airtable_customer_list':
        execution_log.append("Branch B triggered: Airtable Customer List")
        execution_log.append(f"Step 1: Calling airtable_list_records with base_id='{airtable_base_id}', table_name='{airtable_table_name}', max_records=5")
        raw_result = call_tool('airtable_list_records', {
            'base_id': airtable_base_id,
            'table_name': airtable_table_name,
            'max_records': 5
        })
        execution_log.append(f"[RAW] {str(raw_result)[:200]}")
        list_result = json.loads(raw_result) if isinstance(raw_result, str) else raw_result

        # Extract CustomerName and Email
        customers = []
        if list_result and isinstance(list_result, dict) and 'records' in list_result:
            for record in list_result.get('records', []):
                fields = record.get('fields', {})
                customer_name = fields.get('CustomerName')
                email = fields.get('Email')
                if customer_name and email:
                    customers.append({'CustomerName': customer_name, 'Email': email})
        final_result_obj = {'query_type': request_type, 'customers': customers}
    elif request_type == 'mongo_db_stats':
        execution_log.append("Branch C triggered: MongoDB Database Statistics")
        execution_log.append(f"Step 1: Calling mongodb_db-stats with database='{mongo_db_name_stats}'")
        raw_result = call_tool('mongodb_db-stats', {
            'database': mongo_db_name_stats
        })
        execution_log.append(f"[RAW] {str(raw_result)[:200]}")
        stats_result = json.loads(raw_result) if isinstance(raw_result, str) else raw_result
        final_result_obj = {'query_type': request_type, 'stats': stats_result}
    else:
        execution_log.append("Branch D triggered: Unsupported Query")
        final_result_obj = {"message": "Data source or query type not supported."}

    execution_log.append(f"Final result object: {json.dumps(final_result_obj)}")
    return "\n".join(execution_log)

def generate_reference_answer():
    import json
    from mcp_client import call_tool
    from datetime import datetime

    execution_log = []

    # Inputs
    primary_condition = "Alzheimer's Disease"
    intervention_term = "immunotherapy"
    nyc_address = "New York City"
    nyc_lat_default = 40.7128
    nyc_lon_default = -74.0060

    # Step 1: Initial Search for Trials
    execution_log.append(f"Step 1: Searching for clinical trials with condition '{primary_condition}' and intervention '{intervention_term}'.")
    try:
        raw_initial_search = call_tool(
            'clinicaltrialsgov-mcp-server_clinicaltrials_list_studies',
            {
                "query": {
                    "cond": primary_condition,
                    "intr": intervention_term
                },
                "countTotal": True,
                "pageSize": 5 # To get top 5 for moderate branch
            }
        )
        execution_log.append(f"[RAW] {str(raw_initial_search)[:200]}")
        initial_search_results = json.loads(raw_initial_search) if isinstance(raw_initial_search, str) else raw_initial_search
        total_studies = initial_search_results.get('countTotal', 0)
        execution_log.append(f"Initial search found {total_studies} studies.")
    except Exception as e:
        execution_log.append(f"Error during initial search: {e}")
        total_studies = 0 # Assume 0 studies if error

    final_report = {
        "primary_condition": primary_condition,
        "intervention_term": intervention_term,
        "analysis_type": "",
        "results": {}
    }

    # Step 2: Branching based on total_studies count
    if total_studies > 500:
        execution_log.append("Branch A triggered")
        final_report["analysis_type"] = "High Volume Analysis: Phase & Sponsor Trends"

        # Nested Condition: Analyze trends by phase
        execution_log.append("Analyzing trends by phase for high volume studies.")
        try:
            raw_phase_trends = call_tool(
                'clinicaltrialsgov-mcp-server_clinicaltrials_analyze_trends',
                {
                    "query": {
                        "cond": primary_condition,
                        "intr": intervention_term
                    },
                    "analysisType": "countByPhase"
                }
            )
            execution_log.append(f"[RAW] {str(raw_phase_trends)[:200]}")
            phase_trends = json.loads(raw_phase_trends) if isinstance(raw_phase_trends, str) else raw_phase_trends
            final_report["results"]["phase_distribution"] = phase_trends.get('results', {})

            total_studies_in_phase_analysis = sum(item.get('count', 0) for item in phase_trends.get('results', []))
            phase_3_studies = 0
            for item in phase_trends.get('results', []):
                if item.get('key') == 'Phase 3':
                    phase_3_studies = item.get('count', 0)

            # Nested condition: If more than 50% are Phase 3, also analyze by sponsor type
            if total_studies_in_phase_analysis > 0 and (phase_3_studies / total_studies_in_phase_analysis) > 0.5:
                execution_log.append("Nested Branch A.1 triggered")
                execution_log.append("More than 50% studies are Phase 3. Analyzing by sponsor type.")
                try:
                    raw_sponsor_trends = call_tool(
                        'clinicaltrialsgov-mcp-server_clinicaltrials_analyze_trends',
                        {
                            "query": {
                                "cond": primary_condition,
                                "intr": intervention_term
                            },
                            "analysisType": "countBySponsorType"
                        }
                    )
                    execution_log.append(f"[RAW] {str(raw_sponsor_trends)[:200]}")
                    sponsor_trends = json.loads(raw_sponsor_trends) if isinstance(raw_sponsor_trends, str) else raw_sponsor_trends
                    final_report["results"]["sponsor_type_distribution"] = sponsor_trends.get('results', {})
                except Exception as e:
                    execution_log.append(f"Error analyzing sponsor trends: {e}")
            else:
                execution_log.append("Nested Branch A.2 triggered")
                execution_log.append("Less than 50% studies are Phase 3. Skipping sponsor type analysis.")

        except Exception as e:
            execution_log.append(f"Error analyzing phase trends: {e}")

    elif 50 <= total_studies <= 500:
        execution_log.append("Branch B triggered")
        final_report["analysis_type"] = "Moderate Volume Analysis: Top 5 Studies & Recruiting Details"

        top_5_studies_summary = initial_search_results.get('studies', [])
        final_report["results"]["top_5_studies_summary"] = top_5_studies_summary

        detailed_recruiting_studies = []
        recruiting_found = False
        if top_5_studies_summary:
            execution_log.append("Checking top 5 studies for recruiting status.")
            for study in top_5_studies_summary:
                nct_id = study.get('protocolSection', {}).get('identificationModule', {}).get('nctId', '')
                overall_status = study.get('protocolSection', {}).get('statusModule', {}).get('overallStatus', '')

                if nct_id and (overall_status == 'RECRUITING' or overall_status == 'ENROLLING_BY_INVITATION'):
                    recruiting_found = True
                    execution_log.append(f"Nested Branch B.1 triggered")
                    execution_log.append(f"Study {nct_id} is recruiting. Getting full details and calculating duration.")
                    try:
                        raw_study_details = call_tool(
                            'clinicaltrialsgov-mcp-server_clinicaltrials_get_study',
                            {"nctIds": nct_id}
                        )
                        execution_log.append(f"[RAW] {str(raw_study_details)[:200]}")
                        study_details = json.loads(raw_study_details) if isinstance(raw_study_details, str) else raw_study_details

                        full_study_data = study_details.get('studies', [{}])[0]
                        start_date_str = full_study_data.get('protocolSection', {}).get('statusModule', {}).get('startDate', {}).get('date')
                        completion_date_str = full_study_data.get('protocolSection', {}).get('statusModule', {}).get('primaryCompletionDate', {}).get('date')

                        duration_years = None
                        if start_date_str and completion_date_str:
                            execution_log.append(f"Calculating duration for {nct_id}.")
                            try:
                                start_year = datetime.strptime(start_date_str, '%Y-%m-%d').year
                                completion_year = datetime.strptime(completion_date_str, '%Y-%m-%d').year
                                raw_duration_calc = call_tool(
                                    'calculator_calculate',
                                    {"expression": f"{completion_year} - {start_year}"}
                                )
                                execution_log.append(f"[RAW] {str(raw_duration_calc)[:200]}")
                                duration_calc_result = json.loads(raw_duration_calc) if isinstance(raw_duration_calc, str) else raw_duration_calc
                                duration_years = duration_calc_result.get('result')
                            except Exception as calc_e:
                                execution_log.append(f"Error calculating duration for {nct_id}: {calc_e}")

                        detailed_recruiting_studies.append({
                            "nct_id": nct_id,
                            "overall_status": overall_status,
                            "start_date": start_date_str,
                            "completion_date": completion_date_str,
                            "approx_duration_years": duration_years,
                            "full_details_summary": full_study_data.get('protocolSection', {}).get('descriptionModule', {}).get('briefSummary', '')[:100] + '...' # Truncate for brevity
                        })
                    except Exception as e:
                        execution_log.append(f"Error getting detailed study info for {nct_id}: {e}")
            if recruiting_found:
                final_report["results"]["detailed_recruiting_studies"] = detailed_recruiting_studies
            else:
                execution_log.append("Nested Branch B.2 triggered")
                execution_log.append("No recruiting studies found among top 5. Only summary provided.")
        else:
            execution_log.append("No top 5 studies found in moderate volume branch.")


    elif 1 <= total_studies < 50:
        execution_log.append("Branch C triggered")
        final_report["analysis_type"] = "Low Volume Analysis: Local Search or Broader Neuroscience"

        # Nested Condition: Search for related trials in NYC
        execution_log.append(f"Searching for related trials in '{nyc_address}'.")
        try:
            raw_nyc_search = call_tool(
                'clinicaltrialsgov-mcp-server_clinicaltrials_list_studies',
                {
                    "query": {
                        "cond": primary_condition,
                        "intr": intervention_term,
                        "locn": nyc_address
                    },
                    "countTotal": True
                }
            )
            execution_log.append(f"[RAW] {str(raw_nyc_search)[:200]}")
            nyc_search_results = json.loads(raw_nyc_search) if isinstance(raw_nyc_search, str) else raw_nyc_search
            nyc_total_studies = nyc_search_results.get('countTotal', 0)
            final_report["results"]["nyc_studies_count"] = nyc_total_studies
            final_report["results"]["nyc_studies_summary"] = nyc_search_results.get('studies', [])

            if nyc_total_studies > 0:
                execution_log.append("Nested Branch C.1 triggered")
                execution_log.append("NYC-specific search found studies. Finding nearby hospitals.")
                # Get NYC coordinates
                raw_geocode_nyc = call_tool(
                    'osm-mcp-server_geocode_address',
                    {"address": nyc_address}
                )
                execution_log.append(f"[RAW] {str(raw_geocode_nyc)[:200]}")
                geocode_nyc_results = json.loads(raw_geocode_nyc) if isinstance(raw_geocode_nyc, str) else raw_geocode_nyc

                # Assume first result is best
                if geocode_nyc_results and geocode_nyc_results.get('result'):
                    first_nyc_location = geocode_nyc_results['result'][0]
                    nyc_lat_found = first_nyc_location.get('lat', nyc_lat_default)
                    nyc_lon_found = first_nyc_location.get('lon', nyc_lon_default)

                    # Find nearby hospitals
                    raw_nearby_hospitals = call_tool(
                        'osm-mcp-server_find_nearby_places',
                        {
                            "latitude": float(nyc_lat_found),
                            "longitude": float(nyc_lon_found),
                            "radius": 5000,
                            "categories": ["healthcare"],
                            "limit": 5
                        }
                    )
                    execution_log.append(f"[RAW] {str(raw_nearby_hospitals)[:200]}")
                    nearby_hospitals = json.loads(raw_nearby_hospitals) if isinstance(raw_nearby_hospitals, str) else raw_nearby_hospitals

                    final_report["results"]["nearby_hospitals_nyc"] = nearby_hospitals.get('results', {}).get('healthcare', [])
                else:
                    execution_log.append("Could not geocode New York City, skipping nearby hospital search.")
            else:
                execution_log.append("Nested Branch C.2 triggered")
                execution_log.append("NYC-specific search found no studies. Broadening search to 'neuroscience'.")
                try:
                    raw_broad_search = call_tool(
                        'clinicaltrialsgov-mcp-server_clinicaltrials_list_studies',
                        {
                            "query": {
                                "cond": "neuroscience",
                                "intr": intervention_term
                            },
                            "countTotal": True,
                            "pageSize": 5
                        }
                    )
                    execution_log.append(f"[RAW] {str(raw_broad_search)[:200]}")
                    broad_search_results = json.loads(raw_broad_search) if isinstance(raw_broad_search, str) else raw_broad_search
                    final_report["results"]["broad_neuroscience_studies_count"] = broad_search_results.get('countTotal', 0)
                    final_report["results"]["broad_neuroscience_studies_summary"] = broad_search_results.get('studies', [])
                except Exception as e:
                    execution_log.append(f"Error during broad neuroscience search: {e}")
        except Exception as e:
            execution_log.append(f"Error during NYC specific search: {e}")

    else: # total_studies == 0
        execution_log.append("Branch D triggered")
        final_report["analysis_type"] = "No Studies Found: Global Immunotherapy Sponsor Trends"

        # Action: Analyze global trends for "immunotherapy" across all conditions by sponsor type
        execution_log.append("Analyzing global sponsor trends for immunotherapy.")
        try:
            raw_global_sponsor_trends = call_tool(
                'clinicaltrialsgov-mcp-server_clinicaltrials_analyze_trends',
                {
                    "query": {
                        "intr": intervention_term
                    },
                    "analysisType": "countBySponsorType"
                }
            )
            execution_log.append(f"[RAW] {str(raw_global_sponsor_trends)[:200]}")
            global_sponsor_trends = json.loads(raw_global_sponsor_trends) if isinstance(raw_global_sponsor_trends, str) else raw_global_trends
            final_report["results"]["global_immunotherapy_sponsor_distribution"] = global_sponsor_trends.get('results', {})
        except Exception as e:
            execution_log.append(f"Error during global sponsor trend analysis: {e}")

    execution_log.append("Step 3: Aggregating results and generating final report.")
    return json.dumps(final_report, indent=2) + "\n\nExecution Log:\n" + "\n".join(execution_log)
